const jobId = $('generate jobID').first().json.jobId;

return [{
  json: {
    content: [
      {
        type: "text",
        text: JSON.stringify({
          jobId: jobId,
          frameRate: 24,
          totalFrames: 240,
          objects: [
            {
              meshName: "TestCube",
              keyframes: [
                { frame: 0, position: [0, 0, 0], rotation: [0, 0, 0], interpolation: "LINEAR" },
                { frame: 120, position: [0, 0, 0], rotation: [0, 0, 45], interpolation: "LINEAR" },
                { frame: 240, position: [0, 0, 0], rotation: [0, 0, 90], interpolation: "LINEAR" }
              ],
              constraints: []
            }
          ],
          cameraPath: [
            { frame: 0, position: [3, 3, 2], lookAt: [0, 0, 0.5], fov: 50 },
            { frame: 120, position: [2, 4, 2], lookAt: [0, 0, 0.5], fov: 50 },
            { frame: 240, position: [3, 3, 2], lookAt: [0, 0, 0.5], fov: 50 }
          ],
          timingOffsets: {}
        })
      }
    ]
  }
}];

const response = $('Claude Call 2').first().json;

let rawText = '';

if (response.content && Array.isArray(response.content)) {
  rawText = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Claude Call 2: unexpected response shape — no content array');
}

// Strip markdown fences if present
rawText = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error('Claude Call 2: JSON parse failed — ' + e.message + ' | Raw: ' + rawText.substring(0, 300));
}

return [{ json: parsed }];

const parsed = $('Parse Claude Call 2 Response').first().json;
const jobId = $('generate jobID').first().json.jobId;
const intermediatesDir = $('generate jobID').first().json.intermediatesDir;

const jsonString = JSON.stringify(parsed, null, 2);
const binary = Buffer.from(jsonString, 'utf8').toString('base64');

return [{
  json: {
    jobId,
    intermediatesDir,
    fileName: `${jobId}-simulation-execution.json`
  },
  binary: {
